import java.io.*;

public class InsecureDeserializationDemo {

    public static void main(String[] args) {
        String userInput = "serialized_object_here"; // User input containing serialized object

        try {
            // Deserialize the user input
            ByteArrayInputStream byteIn = new ByteArrayInputStream(userInput.getBytes());
            ObjectInputStream objIn = new ObjectInputStream(byteIn);
            Object obj = objIn.readObject();

            // Perform some operation with the deserialized object
            System.out.println(obj.toString());
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

